+        self.merge_debt = LexicalGenerationMergeDebt {
+            state: if pending_shard_count == 0 && pending_artifact_bytes == 0 {
+                LexicalGenerationMergeDebtState::Complete
+            } else {
+                LexicalGenerationMergeDebtState::Pending
+            },
